inline void calculate_macro_xs(double * macro_xs, int mat, double E, Input input,
                               __global int * num_nucs, __global int * mats, int max_num_nucs,
                               __global double * concs, __global int * n_windows,
                               __global double * pseudo_K0RS, __global Window * windows,
                               __global Pole * poles, int max_num_windows, int max_num_poles)
{
	for(int i = 0; i < 4; i++)
		macro_xs[i] = 0.0;

	for(int i = 0; i < num_nucs[mat]; i++)
	{
		double micro_xs[4];
		int nuc = mats[mat * max_num_nucs + i];

		if(input.doppler == 1)
			calculate_micro_xs_doppler(micro_xs, nuc, E, input, n_windows, pseudo_K0RS, windows, poles, max_num_windows, max_num_poles);
		else
			calculate_micro_xs(micro_xs, nuc, E, input, n_windows, pseudo_K0RS, windows, poles, max_num_windows, max_num_poles);

		for(int j = 0; j < 4; j++)
			macro_xs[j] += micro_xs[j] * concs[mat * max_num_nucs + i];
	}
}

__kernel void macro_xs_lookup_kernel(Input in,
                                     __global int * num_nucs,
                                     __global int * mats,
                                     int max_num_nucs,
                                     __global double * concs,
                                     __global int * n_windows,
                                     __global double * pseudo_K0RS,
                                     __global Window * windows,
                                     __global Pole * poles,
                                     int max_num_windows,
                                     int max_num_poles,
                                     __global int * verification_array)
{
	int i = (int)get_global_id(0);
	if(i >= in.lookups)
		return;

	ulong seed = STARTING_SEED;
	seed = fast_forward_LCG(seed, (ulong)(2 * i));

	double E = LCG_random_double(&seed);
	int mat = pick_mat(&seed);

	double macro_xs[4] = {0.0, 0.0, 0.0, 0.0};
	calculate_macro_xs(macro_xs, mat, E, in, num_nucs, mats, max_num_nucs, concs,
	                   n_windows, pseudo_K0RS, windows, poles, max_num_windows, max_num_poles);

	double maxv = -1.7976931348623158e+308;
	int max_idx = 0;
	for(int x = 0; x < 4; x++)
	{
		if(macro_xs[x] > maxv)
		{
			maxv = macro_xs[x];
			max_idx = x;
		}
	}

	verification_array[i] = max_idx + 1;
}

