    sigF += c_mul(pole.MP_RF, faddeeva).r;
  }

  sigE = sigT - sigA;
  micro_xs[0] = sigT;
  micro_xs[1] = sigA;
  micro_xs[2] = sigF;
  micro_xs[3] = sigE;
}

static inline void calculate_macro_xs(double * macro_xs, int mat, double E, Input input,
                                      __global const int * num_nucs,
                                      __global const int * mats,
                                      int max_num_nucs,
                                      __global const double * concs,
                                      __global const int * n_windows,
                                      __global const double * pseudo_K0RS,
                                      __global const Window * windows,
                                      __global const Pole * poles,
                                      int max_num_windows, int max_num_poles)
{
  for(int i = 0; i < 4; i++)
    macro_xs[i] = 0.0;

  for(int i = 0; i < num_nucs[mat]; i++)
  {
    double micro_xs[4];
    int nuc = mats[mat * max_num_nucs + i];

    if(input.doppler == 1)
      calculate_micro_xs_doppler(micro_xs, nuc, E, input, n_windows, pseudo_K0RS, windows, poles, max_num_windows, max_num_poles);
    else
      calculate_micro_xs(micro_xs, nuc, E, input, n_windows, pseudo_K0RS, windows, poles, max_num_windows, max_num_poles);

    for(int j = 0; j < 4; j++)
      macro_xs[j] += micro_xs[j] * concs[mat * max_num_nucs + i];
  }
}

static inline int pick_mat(ulong * seed)
{
  double dist[12];
  dist[0]  = 0.140;
  dist[1]  = 0.052;
  dist[2]  = 0.275;
  dist[3]  = 0.134;
  dist[4]  = 0.154;
  dist[5]  = 0.064;
  dist[6]  = 0.066;
  dist[7]  = 0.055;
  dist[8]  = 0.008;
  dist[9]  = 0.015;
  dist[10] = 0.025;
  dist[11] = 0.013;

  double roll = LCG_random_double(seed);

  for(int i = 0; i < 12; i++)
  {
    double running = 0.0;
    for(int j = i; j > 0; j--)
      running += dist[j];
    if(roll < running)
      return i;
  }

  return 0;
}

__kernel void macro_xs_lookup_kernel(Input in,
                                     __global const int * num_nucs,
                                     __global const int * mats,
                                     int max_num_nucs,
                                     __global const double * concs,
                                     __global const int * n_windows,
                                     __global const double * pseudo_K0RS,
                                     __global const Window * windows,
                                     __global const Pole * poles,
                                     int max_num_windows,
                                     int max_num_poles,
                                     __global int * verification)
{
  int i = (int)get_global_id(0);
  if(i >= in.lookups)
    return;

  ulong seed = (ulong)STARTING_SEED;
  seed = fast_forward_LCG(seed, (ulong)(2 * i));

  double E = LCG_random_double(&seed);
  int mat = pick_mat(&seed);

  double macro_xs[4] = {0.0, 0.0, 0.0, 0.0};
  calculate_macro_xs(macro_xs, mat, E, in, num_nucs, mats, max_num_nucs, concs, n_windows, pseudo_K0RS, windows, poles, max_num_windows, max_num_poles);

  double maxv = -1.7976931348623157e+308;
  int max_idx = 0;
  for(int x = 0; x < 4; x++)
  {
    if(macro_xs[x] > maxv)
    {
      maxv = macro_xs[x];
      max_idx = x;
    }
  }
  verification[i] = max_idx + 1;
}

