inline RSComplex c_add(RSComplex A, RSComplex B)
{
	RSComplex C;
	C.r = A.r + B.r;
	C.i = A.i + B.i;
	return C;
}

inline RSComplex c_sub(RSComplex A, RSComplex B)
{
	RSComplex C;
	C.r = A.r - B.r;
	C.i = A.i - B.i;
	return C;
}

inline RSComplex c_mul(RSComplex A, RSComplex B)
{
	double a = A.r;
	double b = A.i;
	double c = B.r;
	double d = B.i;
	RSComplex C;
	C.r = (a * c) - (b * d);
	C.i = (a * d) + (b * c);
	return C;
}

inline RSComplex c_div(RSComplex A, RSComplex B)
{
	double a = A.r;
	double b = A.i;
	double c = B.r;
	double d = B.i;
	RSComplex C;
	double denom = c * c + d * d;
	C.r = ((a * c) + (b * d)) / denom;
	C.i = ((b * c) - (a * d)) / denom;
	return C;
}

inline double c_abs(RSComplex A)
{
	return sqrt(A.r * A.r + A.i * A.i);
}

inline double fast_exp(double x)
{
	x = 1.0 + x * 0.000244140625;
	x *= x; x *= x; x *= x; x *= x;
	x *= x; x *= x; x *= x; x *= x;
	x *= x; x *= x; x *= x; x *= x;
	return x;
}

inline RSComplex fast_cexp(RSComplex z)
{
	double x = z.r;
	double y = z.i;

	double t1 = fast_exp(x);
	double t2 = cos(y);
	double t3 = sin(y);
	RSComplex t4 = {t2, t3};
	RSComplex t5 = {t1, 0.0};
	return c_mul(t5, t4);
}

inline double LCG_random_double(ulong * seed)
{
	const ulong m = (1UL << 63);
	const ulong a = 2806196910506780709UL;
	const ulong c = 1UL;
	*seed = (a * (*seed) + c) % m;
	return (double)(*seed) / (double)m;
}

inline ulong fast_forward_LCG(ulong seed, ulong n)
{
	const ulong m = (1UL << 63);
	ulong a = 2806196910506780709UL;
	ulong c = 1UL;

	n = n % m;

	ulong a_new = 1UL;
	ulong c_new = 0UL;

	while(n > 0UL)
	{
		if(n & 1UL)
		{
			a_new *= a;
			c_new = c_new * a + c;
		}
		c *= (a + 1UL);
		a *= a;
		n >>= 1UL;
	}

	return (a_new * seed + c_new) % m;
}

